#include <stdio.h>
#include <stdlib.h>

int isValid(const int *A, int N, int D, int T) {
    long long sum = 0;
    for (int i = 0; i < N; ++i) {
        sum += (A[i] + D - 1) / D; // ceil division
        if (sum > T) return 0;    // early exit
    }
    return 1;
}

int main() {
    int Q;
    if (scanf("%d", &Q) != 1) return 0;
    while (Q--) {
        int N, T;
        scanf("%d %d", &N, &T);
        int *A = (int*)malloc(N * sizeof(int));
        int maxA = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &A[i]);
            if (A[i] > maxA) maxA = A[i];
        }
        int left = 1, right = maxA, ans = maxA;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (isValid(A, N, mid, T)) {
                ans = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        printf("%d\n", ans);
        free(A);
    }
    return 0;
}

