            cin >> A[i];
            maxA = max(maxA, A[i]);
        }
        int left = 1, right = maxA, ans = maxA;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (isValid(A, mid, T)) {
                ans = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        cout << ans << '\n';
