#!/usr/bin/env python3
import sys

def is_valid(arr, D, T):
    total = 0
    for v in arr:
        total += (v + D - 1) // D
        if total > T:
            return False
    return True

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    Q = int(next(it))
    out_lines = []
    for _ in range(Q):
        N = int(next(it))
        T = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        left, right = 1, max(arr)
        ans = right
        while left <= right:
            mid = (left + right) // 2
            if is_valid(arr, mid, T):
                ans = mid
                right = mid - 1
            else:
                left = mid + 1
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

